  "critical_findings": [
    {
      "title": "Off-by-one: 1-indexed API contract but 0-indexed offset calculation",
      "risk": "Every request for page=1 skips the first pageSize rows. Customers see their second page of orders as their first page, and the most recent orders are unreachable through the API.",
      "severity": "Critical",
      "location": "getOrderHistory, line: const offset = page * pageSize",
      "reproduction": "Call getOrderHistory('cust-1', 1, 10). Expected: OFFSET 0 (first 10 rows). Actual: OFFSET 10 (rows 11-20). The newest 10 orders are invisible to the caller.",
      "fix": "Change to: const offset = (page - 1) * pageSize;",
      "time_to_fix": "1 minute",
      "acceptance_criteria_affected": "API documentation states pages are 1-indexed; current implementation violates this contract."
    },
    {
      "title": "No input validation on page and pageSize allows DoS and nonsensical queries",
      "risk": "page <= 0 produces negative OFFSET (database error or undefined behavior depending on engine). pageSize = 0 returns nothing. pageSize = 999999999 loads unbounded rows into memory, causing OOM or extreme latency.",
      "severity": "High",
      "location": "getOrderHistory, function parameters",
      "reproduction": "Call getOrderHistory('cust-1', 0, 10) → OFFSET -10, likely DB error. Call getOrderHistory('cust-1', 1, 10000000) → attempts to load millions of rows.",
      "fix": "Add validation at function entry: if (page < 1) throw new Error('page must be >= 1'); if (pageSize < 1 || pageSize > 100) throw new Error('pageSize must be 1-100'); Also validate customerId is non-empty.",
      "time_to_fix": "5 minutes",
      "acceptance_criteria_affected": "Production stability; any public-facing endpoint without bounds is a DoS vector."
    }
  ],

  "important_issues": [
    {
      "title": "No total count returned — clients cannot render pagination controls",
      "description": "The function returns only the page of orders with no indication of total results or whether more pages exist. Clients must guess when to stop paginating. Standard practice is to return { data: Order[], total: number } or include a hasNextPage flag.",
      "location": "getOrderHistory return type: Promise<Order[]>"
    },
    {
      "title": "OFFSET-based pagination degrades at depth",
      "description": "OFFSET N forces the database to scan and discard N rows before returning results. For customers with large order histories, deep pages (e.g., page 500) become progressively slower. Cursor-based pagination (WHERE created_at < $lastSeen) would be O(1) at any depth. Not blocking, but worth noting for scale.",
      "location": "SQL query OFFSET $3"
    }
  ],

